// MARK: - Password Hashing Utility

class PasswordHasher {
    
    /// Generates a random salt of the specified length
    static func generateSalt(length: Int = 32) -> Data {
        var salt = Data(count: length)
        salt.withUnsafeMutableBytes { buffer in
            guard let baseAddress = buffer.baseAddress else { return }
            _ = SecRandomCopyBytes(kSecRandomDefault, length, baseAddress)
        }
        return salt
    }
    
    /// Hashes a password using PBKDF2 with SHA-256
    /// Compatible with iOS 10+ via CommonCrypto
    static func hashPassword(_ password: String, salt: Data, iterations: UInt32 = 100_000, keyLength: Int = 32) -> Data? {
        guard let passwordData = password.data(using: .utf8) else { return nil }
        
        var derivedKey = Data(count: keyLength)
        
        let result = derivedKey.withUnsafeMutableBytes { derivedKeyBuffer in
            salt.withUnsafeBytes { saltBuffer in
                passwordData.withUnsafeBytes { passwordBuffer in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBuffer.baseAddress?.assumingMemoryBound(to: Int8.self),
                        passwordData.count,
                        saltBuffer.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        salt.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA256),
                        iterations,
                        derivedKeyBuffer.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        keyLength
                    )
                }
            }
        }
        
        guard result == kCCSuccess else { return nil }
        return derivedKey
    }
    
    /// Computes SHA-256 hash (for quick integrity checks)
    static func sha256(_ data: Data) -> Data {
        var hash = Data(count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes { dataBuffer in
            hash.withUnsafeMutableBytes { hashBuffer in
                _ = CC_SHA256(
                    dataBuffer.baseAddress,
                    CC_LONG(data.count),
                    hashBuffer.baseAddress?.assumingMemoryBound(to: UInt8.self)
                )
            }
        }
        return hash
    }
    
    /// Constant-time comparison to prevent timing attacks
    static func secureCompare(_ a: Data, _ b: Data) -> Bool {
        guard a.count == b.count else { return false }
        var result: UInt8 = 0
        for i in 0..<a.count {
            result |= a[i] ^ b[i]
        }
        return result == 0
    }
}

// MARK: - Stored Password Model

struct StoredPassword: Codable {
    let identifier: String
    let hashedPassword: Data
    let salt: Data
    let iterations: UInt32
    let keyLength: Int
    let createdAt: Date
    let updatedAt: Date
    
    var isExpired: Bool {
        // Passwords expire after 90 days, requiring re-authentication online
        let expirationInterval: TimeInterval = 90 * 24 * 60 * 60
        return Date().timeIntervalSince(updatedAt) > expirationInterval
    }
}

