// MARK: - Brute Force Protection

class BruteForceProtection {
    
    static let shared = BruteForceProtection()
    
    private var attemptCounts: [String: Int] = [:]
    private var lockoutTimes: [String: Date] = [:]
    private let maxAttempts = 5
    private let lockoutDuration: TimeInterval = 300 // 5 minutes
    private let queue = DispatchQueue(label: "com.bruteforce.queue")
    
    private init() {}
    
    func canAttempt(forIdentifier identifier: String) -> (allowed: Bool, remainingSeconds: Int) {
        var result: (Bool, Int) = (true, 0)
        queue.sync {
            if let lockoutTime = lockoutTimes[identifier] {
                let elapsed = Date().timeIntervalSince(lockoutTime)
                if elapsed < lockoutDuration {
                    let remaining = Int(lockoutDuration - elapsed)
                    result = (false, remaining)
                    return
                } else {
                    // Lockout expired, reset
                    lockoutTimes.removeValue(forKey: identifier)
                    attemptCounts.removeValue(forKey: identifier)
                }
            }
            result = (true, 0)
        }
        return result
    }
    
    func recordFailedAttempt(forIdentifier identifier: String) {
        queue.sync {
            let count = (attemptCounts[identifier] ?? 0) + 1
            attemptCounts[identifier] = count
            if count >= maxAttempts {
                lockoutTimes[identifier] = Date()
            }
        }
    }
    
    func resetAttempts(forIdentifier identifier: String) {
        queue.sync {
            attemptCounts.removeValue(forKey: identifier)
            lockoutTimes.removeValue(forKey: identifier)
        }
    }
    
    func remainingAttempts(forIdentifier identifier: String) -> Int {
        var result = maxAttempts
        queue.sync {
            result = maxAttempts - (attemptCounts[identifier] ?? 0)
        }
        return max(0, result)
    }
}

