    @objc private func storePasswordTapped() {
        guard let inputs = validateInputs() else { return }
        
        // Validate password strength
        if inputs.password.count < 8 {
            showStatus("⚠️ Password must be at least 8 characters", isError: true)
            return
        }
        
        setLoading(true)
        
        storage.storePassword(inputs.password, forIdentifier: inputs.identifier) { [weak self] success in
            self?.setLoading(false)
            if success {
                self?.showStatus("✅ Password stored securely for '\(inputs.identifier)'", isError: false)
                self?.passwordTextField.text = ""
                self?.bruteForce.resetAttempts(forIdentifier: inputs.identifier)
                self?.refreshAccountsList()
            } else {
                self?.showStatus("❌ Failed to store password", isError: true)
            }
        }
    }
    
