        guard let inputs = validateInputs() else { return }
        
        // Check brute force protection
        let (allowed, remainingSeconds) = bruteForce.canAttempt(forIdentifier: inputs.identifier)
        guard allowed else {
            let minutes = remainingSeconds / 60
            let seconds = remainingSeconds % 60
            showStatus("🔒 Account locked. Try again in \(minutes)m \(seconds)s", isError: true)
            return
        }
        
        setLoading(true)
        
        storage.verifyPassword(inputs.password, forIdentifier: inputs.identifier) { [weak self] result in
            self?.setLoading(false)
            
            switch result {
            case .success:
                self?.showStatus("✅ \(result.message)", isError: false)
                self?.bruteForce.resetAttempts(forIdentifier: inputs.identifier)
                self?.passwordTextField.text = ""
                
            case .incorrectPassword:
                self?.bruteForce.recordFailedAttempt(forIdentifier: inputs.identifier)
                let remaining = self?.bruteForce.remainingAttempts(forIdentifier: inputs.identifier) ?? 0
                self?.showStatus("❌ \(result.message). \(remaining) attempts remaining.", isError: true)
                
            case .notFound:
                self?.showStatus("⚠️ \(result.message)", isError: true)
                
            case .expired:
                self?.showStatus("⏰ \(result.message)", isError: true)
                
            case .error(let msg):
                self?.showStatus("❌ \(msg)", isError: true)
            }
        }
    }
    
