    }
    
    private func refreshAccountsList() {
        storage.allIdentifiers { [weak self] identifiers in
            if identifiers.isEmpty {
                self?.accountsLabel.text = "Stored Accounts: None"
            } else {
                let list = identifiers.joined(separator: ", ")
                self?.accountsLabel.text = "Stored Accounts (\(identifiers.count)):\n\(list)"
            }
        }
    }
}

// MARK: - App Delegate

@UIApplicationMain
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        window = UIWindow(frame: UIScreen.main.bounds)
        window?.rootViewController = UINavigationController(rootViewController: PasswordViewController())
        window?.makeKeyAndVisible()
        return true
    }
}